import rateLimit from 'express-rate-limit';

export const loginRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  keyGenerator: (req) => req.body?.email ?? req.ip,
  message: { error: 'Too many login attempts, please try again in 15 minutes' },
});

