import { describe, it, expect } from '@jest/globals';
import request from 'supertest';
import { createApp } from '../../src/app';

describe('rate limiter + OAuth interaction', () => {
  it('does not count OAuth callbacks against login rate limit', async () => {
    const app = createApp();
    // Simulate 5 OAuth callbacks
    for (let i = 0; i < 5; i++) {
      await request(app).get('/auth/oauth/google/callback?code=test&state=test');
    }
    // Login should still work (not rate-limited)
    const res = await request(app).post('/auth/login').send({ email: 'user@test.com', password: 'pass' });
    expect(res.status).not.toBe(429);
  });

  it('still rate-limits login attempts by email', async () => {
    const app = createApp();
    for (let i = 0; i < 6; i++) {
      await request(app).post('/auth/login').send({ email: 'brute@test.com', password: 'wrong' });
    }
    const res = await request(app).post('/auth/login').send({ email: 'brute@test.com', password: 'wrong' });
    expect(res.status).toBe(429);
  });
});

